import{statSync}from"node:fs";import{stat}from"node:fs/promises";import{delimiter}from"node:path";export const isexe=async(t,r={})=>{const{ignoreErrors:e=!1}=r;try{return checkStat(await stat(t),t,r)}catch(t){const r=t;if(e||"EACCES"===r.code)return!1;throw r}};export const sync=(t,r={})=>{const{ignoreErrors:e=!1}=r;try{return checkStat(statSync(t),t,r)}catch(t){const r=t;if(e||"EACCES"===r.code)return!1;throw r}};const checkPathExt=(t,r)=>{const{pathExt:e=process.env.PATHEXT||""}=r,o=e.split(delimiter);if(-1!==o.indexOf(""))return!0;for(const r of o){const e=r.toLowerCase(),o=t.substring(t.length-e.length).toLowerCase();if(e&&o===e)return!0}return!1},checkStat=(t,r,e)=>t.isFile()&&checkPathExt(r,e);